* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
  background-color: #f5f5f5;
  color: #333;
  font-size: 14px;
}

.container {
  display: flex;
  height: 100vh;
  gap: 0;
}

.panel {
  flex: 1;
  background-color: #ffffff;
  overflow-y: auto;
  border-right: 1px solid #e0e0e0;
}

.panel:last-child {
  border-right: none;
}

.panel-header {
  background-color: #e8e8e8;
  padding: 15px 20px;
  border-bottom: 1px solid #d0d0d0;
  position: sticky;
  top: 0;
  z-index: 10;
}

.panel-header h2 {
  font-size: 16px;
  font-weight: 600;
  color: #333;
}

/* 좌측 패널: 정보 테이블 */
.info-table {
  padding: 20px;
  border-bottom: 1px solid #e0e0e0;
}

.table-header {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 10px;
  font-weight: 600;
  background-color: #f9f9f9;
  padding: 12px;
  border: 1px solid #e0e0e0;
  border-radius: 4px;
  margin-bottom: 10px;
}

.table-row {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 10px;
  padding: 12px;
  border: 1px solid #e0e0e0;
  border-radius: 4px;
}

.table-cell {
  padding: 8px;
  word-break: break-word;
  font-size: 13px;
  line-height: 1.4;
}

/* 대화 상세 섹션 */
.chat-section {
  padding: 20px;
}

.chat-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
}

.chat-header h3 {
  font-size: 15px;
  font-weight: 600;
  color: #333;
}

.view-original-btn {
  background: none;
  border: none;
  color: #4a7fc1;
  cursor: pointer;
  font-size: 13px;
  text-decoration: underline;
  padding: 4px 8px;
  border-radius: 4px;
  transition: background-color 0.2s;
}

.view-original-btn:hover {
  background-color: #f0f0f0;
}

.chat-datetime {
  font-size: 12px;
  color: #999;
  margin-bottom: 15px;
}

.chat-messages {
  display: flex;
  flex-direction: column;
  gap: 12px;
  max-height: 400px;
  overflow-y: auto;
}

.message {
  display: flex;
  gap: 10px;
  margin-bottom: 8px;
}

.message-avatar {
  font-size: 24px;
  flex-shrink: 0;
  width: 36px;
  height: 36px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.message-content {
  display: flex;
  flex-direction: column;
  gap: 4px;
  max-width: 60%;
}

.message-text {
  padding: 10px 12px;
  border-radius: 8px;
  line-height: 1.5;
  word-break: break-word;
  font-size: 13px;
}

.user-message {
  justify-content: flex-start;
}

.user-message .message-text {
  background-color: #f5f5f5;
  border: 1px solid #e0e0e0;
  color: #333;
}

.agent-message {
  justify-content: flex-end;
}

.agent-message .message-content {
  align-items: flex-end;
}

.agent-message .message-text {
  background-color: #4a7fc1;
  color: #ffffff;
}

.message-time {
  font-size: 11px;
  color: #999;
  padding: 0 12px;
}

/* 우측 패널: 체크리스트 */
.checklist {
  padding: 20px;
}

.checklist-category {
  margin-bottom: 20px;
}

.category-header {
  padding: 12px 16px;
  font-weight: 600;
  color: #ffffff;
  border-radius: 4px 4px 0 0;
  font-size: 14px;
}

.category-header.purple {
  background-color: #7c5cbf;
}

.category-header.blue {
  background-color: #4a7fc1;
}

.category-header.orange {
  background-color: #d97706;
}

.category-items {
  background-color: #fafafa;
  border: 1px solid #e0e0e0;
  border-top: none;
  border-radius: 0 0 4px 4px;
  padding: 0;
}

.checklist-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px 16px;
  border-bottom: 1px solid #e0e0e0;
  transition: background-color 0.2s;
}

.checklist-item:last-child {
  border-bottom: none;
}

.checklist-item:hover {
  background-color: #f5f5f5;
}

.checklist-input {
  width: 18px;
  height: 18px;
  cursor: pointer;
  flex-shrink: 0;
}

.checklist-item label {
  flex: 1;
  cursor: pointer;
  user-select: none;
  color: #333;
  font-size: 13px;
}

.item-points {
  color: #999;
  font-size: 12px;
  font-weight: 500;
  min-width: 30px;
  text-align: right;
  flex-shrink: 0;
}

/* 총점 표시 */
.total-score {
  padding: 20px;
  background-color: #f5f5f5;
  border-top: 2px solid #e0e0e0;
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-top: 20px;
}

.score-text {
  font-size: 16px;
  font-weight: 600;
  color: #333;
}

#currentScore {
  color: #d97706;
  font-weight: 700;
  font-size: 18px;
}

.page-info {
  font-size: 12px;
  color: #999;
}

/* 스크롤바 스타일 */
.chat-messages::-webkit-scrollbar {
  width: 6px;
}

.chat-messages::-webkit-scrollbar-track {
  background: transparent;
}

.chat-messages::-webkit-scrollbar-thumb {
  background: #d0d0d0;
  border-radius: 3px;
}

.chat-messages::-webkit-scrollbar-thumb:hover {
  background: #a0a0a0;
}

/* 반응형 디자인 */
@media (max-width: 1200px) {
  .message-content {
    max-width: 70%;
  }
}

@media (max-width: 768px) {
  .container {
    flex-direction: column;
  }

  .panel {
    border-right: none;
    border-bottom: 1px solid #e0e0e0;
  }

  .message-content {
    max-width: 85%;
  }
}

